// ── Patient: Dashboard ─────────────────────────────────────
function PatientDashboard({ user, setPage }) {
  const [stats, setStats] = useState({ appointments: 0, upcoming: 0, completed: 0 });
  const [recent, setRecent] = useState([]);

  useEffect(() => {
    api.get(`/appointments/patient/${user.user_id}`).then(data => {
      setRecent(data.slice(0, 5));
      setStats({
        appointments: data.length,
        upcoming: data.filter(a => a.status === 'confirmed' || a.status === 'pending').length,
        completed: data.filter(a => a.status === 'completed').length,
      });
    });
  }, []);

  return (
    <div>
      <div className="page-header">
        <div className="page-title">Good day, {user.name}! 👋</div>
        <div className="page-subtitle">Here's your health overview</div>
      </div>

      <div className="stats-grid">
        <div className="stat-card">
          <div className="stat-icon blue"><Icon name="calendar" size={22} /></div>
          <div><div className="stat-value">{stats.appointments}</div><div className="stat-label">Total Appointments</div></div>
        </div>
        <div className="stat-card">
          <div className="stat-icon green"><Icon name="clock" size={22} /></div>
          <div><div className="stat-value">{stats.upcoming}</div><div className="stat-label">Upcoming</div></div>
        </div>
        <div className="stat-card">
          <div className="stat-icon yellow"><Icon name="check" size={22} /></div>
          <div><div className="stat-value">{stats.completed}</div><div className="stat-label">Completed</div></div>
        </div>
      </div>

      <div className="card">
        <div className="card-header">
          <span className="card-title">Recent Appointments</span>
          <button className="btn btn-outline btn-sm" onClick={() => setPage('appointments')}>View All</button>
        </div>
        {recent.length === 0 ? (
          <div className="empty-state">
            <Icon name="calendar" size={48} />
            <p>No appointments yet. <span className="auth-link" onClick={() => setPage('doctors')}>Book one now</span></p>
          </div>
        ) : (
          <div className="table-wrap">
            <table>
              <thead><tr><th>Doctor</th><th>Date & Time</th><th>Status</th></tr></thead>
              <tbody>
                {recent.map(a => (
                  <tr key={a.id}>
                    <td><strong>Dr. {a.doctor_name}</strong><div style={{ fontSize: 12, color: '#718096' }}>{a.doctor_specialty}</div></td>
                    <td>{a.date} at {a.time_slot}</td>
                    <td><span className={`badge badge-${a.status}`}>{a.status}</span></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}

// ── Patient: Find Doctors ──────────────────────────────────
function FindDoctors({ user, setPage, setSelectedDoctor }) {
  const [doctors, setDoctors] = useState([]);
  const [search, setSearch] = useState('');
  const [specialty, setSpecialty] = useState('');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    api.get('/doctors').then(data => { setDoctors(data); setLoading(false); });
  }, []);

  const specialties = [...new Set(doctors.map(d => d.specialty).filter(Boolean))];
  const filtered = doctors.filter(d =>
    (d.name.toLowerCase().includes(search.toLowerCase()) || d.specialty?.toLowerCase().includes(search.toLowerCase())) &&
    (!specialty || d.specialty === specialty)
  );

  return (
    <div>
      <div className="page-header">
        <div className="page-title">Find a Doctor</div>
        <div className="page-subtitle">Browse our verified healthcare professionals</div>
      </div>

      <div style={{ display: 'flex', gap: 12, marginBottom: 24 }}>
        <div style={{ flex: 1, position: 'relative' }}>
          <input className="form-input" placeholder="Search by name or specialty..." value={search} onChange={e => setSearch(e.target.value)} style={{ paddingLeft: 40 }} />
          <span style={{ position: 'absolute', left: 12, top: '50%', transform: 'translateY(-50%)', color: '#718096' }}><Icon name="search" size={16} /></span>
        </div>
        <select className="form-select" style={{ width: 200 }} value={specialty} onChange={e => setSpecialty(e.target.value)}>
          <option value="">All Specialties</option>
          {specialties.map(s => <option key={s} value={s}>{s}</option>)}
        </select>
      </div>

      {loading ? <div className="loading">Loading doctors...</div> : (
        <div className="doctors-grid">
          {filtered.map(doc => (
            <div key={doc.id} className="doctor-card" onClick={() => { setSelectedDoctor(doc); setPage('doctor-detail'); }}>
              <div className="doctor-card-header">
                <div className="doctor-avatar">
                  {doc.profile_image ? <img src={`http://localhost:5000${doc.profile_image}`} alt="" /> : doc.name[0]}
                </div>
                <div className="doctor-name">Dr. {doc.name}</div>
                <div className="doctor-specialty">{doc.specialty}</div>
              </div>
              <div className="doctor-card-body">
                <div className="doctor-meta">
                  <div className="doctor-fee">${doc.consultation_fee}</div>
                  <div className="doctor-exp">{doc.experience_years} yrs exp.</div>
                </div>
                <div style={{ fontSize: 13, color: '#4a5568', marginBottom: 12, display: '-webkit-box', WebkitLineClamp: 2, WebkitBoxOrient: 'vertical', overflow: 'hidden' }}>
                  {doc.bio || 'Experienced medical professional.'}
                </div>
                <button className="btn btn-primary" style={{ width: '100%', justifyContent: 'center' }}>
                  Book Appointment
                </button>
              </div>
            </div>
          ))}
          {filtered.length === 0 && (
            <div className="empty-state" style={{ gridColumn: '1/-1' }}>
              <Icon name="search" size={48} />
              <p>No doctors found.</p>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

