        <div className="page-title">Doctor Management</div>
        <div className="page-subtitle">Review and approve doctor applications</div>
      </div>

      <div className="tabs">
        {['pending', 'approved', 'rejected', 'all'].map(f => (
          <button key={f} className={`tab ${filter === f ? 'active' : ''}`} onClick={() => setFilter(f)} style={{ textTransform: 'capitalize' }}>
            {f} {f !== 'all' && `(${doctors.filter(d => d.status === f).length})`}
          </button>
        ))}
      </div>

      {loading ? <div className="loading">Loading...</div> : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
          {filtered.length === 0 && <div className="empty-state card"><Icon name="user" size={48} /><p>No doctors in this category.</p></div>}
          {filtered.map(doc => (
            <div key={doc.id} className="card">
              <div style={{ display: 'flex', gap: 20, alignItems: 'flex-start' }}>
                <div className="doctor-avatar" style={{ width: 72, height: 72, borderRadius: '50%', flexShrink: 0, border: '2px solid #e2e8f0', overflow: 'hidden', display: 'flex', alignItems: 'center', justifyContent: 'center', background: '#dbeafe', color: '#2563eb', fontSize: 24, fontWeight: 700 }}>
                  {doc.profile_image ? <img src={`http://localhost:5000${doc.profile_image}`} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }} /> : doc.name[0]}
                </div>
                <div style={{ flex: 1 }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                    <div>
                      <div style={{ fontWeight: 600, fontSize: 16 }}>Dr. {doc.name}</div>
                      <div style={{ fontSize: 13, color: '#4a5568' }}>{doc.specialty} • {doc.experience_years} yrs • ${doc.consultation_fee}/visit</div>
                      <div style={{ fontSize: 13, color: '#718096', marginTop: 4 }}>{doc.email}</div>
                    </div>
                    <span className={`badge badge-${doc.status}`}>{doc.status}</span>
                  </div>
                  {doc.bio && <p style={{ fontSize: 13, color: '#4a5568', margin: '8px 0' }}>{doc.bio}</p>}
                  <div style={{ display: 'flex', gap: 12, marginTop: 12, flexWrap: 'wrap', alignItems: 'center' }}>
                    {doc.degree_image && (
                      <button className="btn btn-outline btn-sm" onClick={() => setImgViewer(`http://localhost:5000${doc.degree_image}`)}>
                        <Icon name="award" size={14} /> View Degree
                      </button>
                    )}
                    {doc.status !== 'approved' && (
                      <button className="btn btn-success btn-sm" onClick={() => updateStatus(doc.id, 'approved')}>
                        <Icon name="check" size={14} /> Approve
                      </button>
                    )}
                    {doc.status !== 'rejected' && (
                      <button className="btn btn-danger btn-sm" onClick={() => updateStatus(doc.id, 'rejected')}>
                        <Icon name="x" size={14} /> Reject
                      </button>
                    )}
                    {doc.status !== 'pending' && (
                      <button className="btn btn-outline btn-sm" onClick={() => updateStatus(doc.id, 'pending')}>
                        Reset to Pending
                      </button>
                    )}
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

// ── Admin: All Appointments ────────────────────────────────
function AdminAppointments() {
  const [appts, setAppts] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Fetch for all doctors (admin view - we'll get all appointments via a workaround)
    api.get('/admin/doctors').then(async (docs) => {
      const all = [];
      for (const d of docs) {
        const da = await api.get(`/appointments/doctor/${d.id}`);
        all.push(...da);
      }
      // deduplicate
      const seen = new Set();
      const unique = all.filter(a => { if (seen.has(a.id)) return false; seen.add(a.id); return true; });
      setAppts(unique.sort((a, b) => new Date(b.created_at) - new Date(a.created_at)));
      setLoading(false);
    });
  }, []);

  return (
    <div>
      <div className="page-header">
        <div className="page-title">All Appointments</div>
        <div className="page-subtitle">{appts.length} total across the platform</div>
      </div>
      <div className="card">
        {loading ? <div className="loading">Loading...</div> : appts.length === 0 ? (
          <div className="empty-state"><Icon name="calendar" size={48} /><p>No appointments yet.</p></div>
        ) : (
          <div className="table-wrap">
            <table>
              <thead><tr><th>Patient</th><th>Doctor</th><th>Date & Time</th><th>Status</th></tr></thead>
              <tbody>
                {appts.map(a => (
                  <tr key={a.id}>
                    <td><strong>{a.patient_name}</strong></td>
                    <td>Dr. {a.doctor_name}<div style={{ fontSize: 12, color: '#718096' }}>{a.doctor_specialty}</div></td>
                    <td>{a.date} at {a.time_slot}</td>
                    <td><span className={`badge badge-${a.status}`}>{a.status}</span></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}

// ── Main App ───────────────────────────────────────────────
export default function App() {
  const [user, setUser] = useState(null);
  const [doctorProfile, setDoctorProfile] = useState(null);
  const [page, setPage] = useState('home');
  const [selectedDoctor, setSelectedDoctor] = useState(null);

  const defaultPage = (u) => {
    if (u.role === 'admin') return 'admin-dashboard';
    if (u.role === 'doctor') return 'doc-dashboard';
    return 'home';
  };

  const handleLogin = async (userData) => {
    setUser(userData);
    if (userData.role === 'doctor' && userData.doctor_id) {
      const dp = await api.get(`/doctors/${userData.doctor_id}`);
      setDoctorProfile(dp);
    }
    setPage(defaultPage(userData));
  };

  const handleLogout = () => { setUser(null); setDoctorProfile(null); setPage('home'); };

  const navigate = (p, extra = {}) => {
    if (extra.doctor) setSelectedDoctor(extra.doctor);
    setPage(p);
  };

  if (!user) return (
    <>
      <style>{styles}</style>
      <AuthPage onLogin={handleLogin} />
    </>
  );

  const renderPage = () => {
    // Patient pages
    if (page === 'home') return <PatientDashboard user={user} setPage={setPage} />;
    if (page === 'doctors') return <FindDoctors user={user} setPage={setPage} setSelectedDoctor={setSelectedDoctor} />;
    if (page === 'doctor-detail') return <DoctorDetail doctor={selectedDoctor} user={user} onBack={() => setPage('doctors')} />;
    if (page === 'appointments') return <PatientAppointments user={user} />;
    if (page === 'chat') return <ChatPage user={user} doctorProfile={doctorProfile} />;
    // Doctor pages
    if (page === 'doc-dashboard') return <DoctorDashboard user={user} doctorProfile={doctorProfile} />;
    if (page === 'doc-appointments') return <DoctorAppointments user={user} doctorProfile={doctorProfile} />;
    if (page === 'doc-profile') return <DoctorProfile user={user} doctorProfile={doctorProfile} setDoctorProfile={setDoctorProfile} />;
    if (page === 'doc-chat') return <ChatPage user={user} doctorProfile={doctorProfile} />;
    // Admin pages
    if (page === 'admin-dashboard') return <AdminDashboard />;
    if (page === 'admin-doctors') return <AdminDoctors />;
    if (page === 'admin-appointments') return <AdminAppointments />;
    return <div className="empty-state"><p>Page not found.</p></div>;
  };

  return (
    <>
      <style>{styles}</style>
      <div className="app">
        <Sidebar user={user} doctorProfile={doctorProfile} activePage={page} setPage={setPage} onLogout={handleLogout} />
        <main className="main">
          {renderPage()}
        </main>
      </div>
    </>
  );
}
